diff --git a/packages/svelte/src/internal/client/dom/elements/bindings/input.js b/packages/svelte/src/internal/client/dom/elements/bindings/input.js
index 67e6ff1dd..5eb2597c2 100644
--- a/packages/svelte/src/internal/client/dom/elements/bindings/input.js
+++ b/packages/svelte/src/internal/client/dom/elements/bindings/input.js
@@ -85,7 +85,17 @@ export function bind_value(input, get, set = get) {
 			//
 			// <input bind:value={query}>
 			// <p>{await find(query)}</p>
-			if (batches.has(batch)) {
+			//
+			// However, if we're no longer in the same batch that originated from this input
+			// event, we *do* want to update the input value, otherwise two-way bindings that
+			// update via indirection (e.g. writing through a store/class method) will appear
+			// to lag by one keystroke.
+			// Never rewrite the contents of a focused input *during* the batch
+			// that originated from this input event. If we're outside of that
+			// batch (e.g. because the setter caused state replacement), we must
+			// allow rewriting, otherwise the UI can lag by one keystroke.
+			if (batch !== null && batches.has(batch)) {
+				queue_micro_task(() => batches.delete(batch));
 				return;
 			}
 		}
