content.content:
     1→/** @import { CallExpression, Expression, Pattern } from 'estree' */
     2→/** @import { AST } from '#compiler' */
     3→/** @import { ComponentContext } from '../types' */
     4→import { dev, is_ignored } from '../../../../state.js';
     5→import { is_text_attribute } from '../../../../utils/ast.js';
     6→import * as b from '#compiler/builders';
     7→import { binding_properties } from '../../../bindings.js';
     8→import { build_attribute_value } from './shared/element.js';
     9→import { build_bind_this, validate_binding } from './shared/utils.js';
    10→
    11→/**
    12→ * @param {AST.BindDirective} node
    13→ * @param {ComponentContext} context
    14→ */
    15→export function BindDirective(node, context) {
    16→	const expression = /** @type {Expression} */ (context.visit(node.expression));
    17→	const property = binding_properties[node.name];
    18→
    19→	const parent = /** @type {AST.SvelteNode} */ (context.path.at(-1));
    20→
    21→	let get, set;
    22→
    23→	if (expression.type === 'SequenceExpression') {
    24→		[get, set] = expression.expressions;
    25→	} else {
    26→		if (
    27→			dev &&
    28→			context.state.analysis.runes &&
    29→			expression.type === 'MemberExpression' &&
    30→			(node.name !== 'this' ||
    31→				context.path.some(
    32→					({ type }) =>
    33→						type === 'IfBlock' ||
    34→						type === 'EachBlock' ||
    35→						type === 'AwaitBlock' ||
    36→						type === 'KeyBlock'
    37→				)) &&
    38→			!is_ignored(node, 'binding_property_non_reactive')
    39→		) {
    40→			validate_binding(context.state, node, expression);
    41→		}
    42→
    43→		get = b.thunk(expression);
    44→
    45→		/** @type {Expression | undefined} */
    46→		set = b.unthunk(
    47→			b.arrow(
    48→				[b.id('$$value')],
    49→				/** @type {Expression} */ (
    50→					context.visit(
    51→						b.assignment('=', /** @type {Pattern} */ (node.expression), b.id('$$value'))
    52→					)
    53→				)
    54→			)
    55→		);
    56→
    57→		if (get === set) {
    58→			set = undefined;
    59→		}
    60→	}
    61→
    62→	/** @type {CallExpression} */
    63→	let call;
    64→
    65→	if (property?.event) {
    66→		call = b.call(
    67→			'$.bind_property',
    68→			b.literal(node.name),
    69→			b.literal(property.event),
    70→			context.state.node,
    71→			set ?? get,
    72→			property.bidirectional && get
    73→		);
    74→	} else {
    75→		// special cases
    76→		switch (node.name) {
    77→			// window
    78→			case 'online':
    79→				call = b.call(`$.bind_online`, set ?? get);
    80→				break;
    81→
    82→			case 'scrollX':
    83→			case 'scrollY':
    84→				call = b.call(
    85→					'$.bind_window_scroll',
    86→					b.literal(node.name === 'scrollX' ? 'x' : 'y'),
    87→					get,
    88→					set
    89→				);
    90→				break;
    91→
    92→			case 'innerWidth':
    93→			case 'innerHeight':
    94→			case 'outerWidth':
    95→			case 'outerHeight':
    96→				call = b.call('$.bind_window_size', b.literal(node.name), set ?? get);
    97→				break;
    98→
    99→			// document
   100→			case 'activeElement':
   101→				call = b.call('$.bind_active_element', set ?? get);
   102→				break;
   103→
   104→			// media
   105→			case 'muted':
   106→				call = b.call(`$.bind_muted`, context.state.node, get, set);
   107→				break;
   108→			case 'paused':
   109→				call = b.call(`$.bind_paused`, context.state.node, get, set);
   110→				break;
   111→			case 'volume':
   112→				call = b.call(`$.bind_volume`, context.state.node, get, set);
   113→				break;
   114→			case 'playbackRate':
   115→				call = b.call(`$.bind_playback_rate`, context.state.node, get, set);
   116→				break;
   117→			case 'currentTime':
   118→				call = b.call(`$.bind_current_time`, context.state.node, get, set);
   119→				break;
   120→			case 'buffered':
   121→				call = b.call(`$.bind_buffered`, context.state.node, set ?? get);
   122→				break;
   123→			case 'played':
   124→				call = b.call(`$.bind_played`, context.state.node, set ?? get);
   125→				break;
   126→			case 'seekable':
   127→				call = b.call(`$.bind_seekable`, context.state.node, set ?? get);
   128→				break;
   129→			case 'seeking':
   130→				call = b.call(`$.bind_seeking`, context.state.node, set ?? get);
   131→				break;
   132→			case 'ended':
   133→				call = b.call(`$.bind_ended`, context.state.node, set ?? get);
   134→				break;
   135→			case 'readyState':
   136→				call = b.call(`$.bind_ready_state`, context.state.node, set ?? get);
   137→				break;
   138→
   139→			// dimensions
   140→			case 'contentRect':
   141→			case 'contentBoxSize':
   142→			case 'borderBoxSize':
   143→			case 'devicePixelContentBoxSize':
   144→				call = b.call(
   145→					'$.bind_resize_observer',
   146→					context.state.node,
   147→					b.literal(node.name),
   148→					set ?? get
   149→				);
   150→				break;
   151→
   152→			case 'clientWidth':
   153→			case 'clientHeight':
   154→			case 'offsetWidth':
   155→			case 'offsetHeight':
   156→				call = b.call('$.bind_element_size', context.state.node, b.literal(node.name), set ?? get);
   157→				break;
   158→
   159→			// various
   160→			case 'value': {
   161→				if (parent?.type === 'RegularElement' && parent.name === 'select') {
   162→					call = b.call(`$.bind_select_value`, context.state.node, get, set);
   163→				} else {
   164→					call = b.call(`$.bind_value`, context.state.node, get, set);
   165→				}
   166→				break;
   167→			}
   168→
   169→			case 'files':
   170→				call = b.call(`$.bind_files`, context.state.node, get, set);
   171→				break;
